=INSERT OR IGNORE INTO telegram_context (chat_id, message_id, sender_id, chat_title, message, source, date)
VALUES (
  {{$json.chat_id}},
  {{$json.message_id}},
  {{$json.sender_id === null ? 'NULL' : $json.sender_id}},
  {{$json.chat_title ? ''' + $json.chat_title.replace(/\'/g, "''") + ''' : 'NULL'}},
  '{{ $json.message.replace(/\'/g, "''") }}',
  '{{ $json.source.replace(/\'/g, "''") }}',
  {{$json.date ? ''' + $json.date + ''' : 'NULL'}}
);

CREATE INDEX IF NOT EXISTS idx_telegram_context_chat_date
ON telegram_context(chat_id, date DESC);
